// ─── Gear piece type (ATK vs DEF determines heroMain field name) ─────────────
export const GEAR_TYPE = {
  'Guardian Goggles':'ATK','Guardian Gauntlets':'DEF','Guardian Belt':'DEF','Guardian Boots':'ATK',
  'Sniper Goggles':'ATK','Sniper Gauntlets':'DEF','Sniper Belt':'DEF','Sniper Boots':'ATK',
  'Saboteur Goggles':'ATK','Saboteur Gauntlets':'DEF','Saboteur Belt':'DEF','Saboteur Boots':'ATK',
};

// ─── Hero → Gear Set mapping ──────────────────────────────────────────────────
export const HERO_GEAR_SET = {
  Infantry: { Goggles:'Guardian Goggles', Gauntlets:'Guardian Gauntlets', Belt:'Guardian Belt', Boots:'Guardian Boots' },
  Marksman: { Goggles:'Sniper Goggles',   Gauntlets:'Sniper Gauntlets',   Belt:'Sniper Belt',   Boots:'Sniper Boots'   },
  Lancer:   { Goggles:'Saboteur Goggles', Gauntlets:'Saboteur Gauntlets', Belt:'Saboteur Belt', Boots:'Saboteur Boots' },
};

// ─── Slot → Gear name mapping ─────────────────────────────────────────────────
// App uses "Gloves" for slot name; handoff uses "Gauntlets" for gear name
export const SLOT_TO_GEAR = (troopType, slot) => {
  const set = HERO_GEAR_SET[troopType];
  if (!set) return null;
  const map = { Goggles:'Goggles', Gloves:'Gauntlets', Belt:'Belt', Boots:'Boots' };
  return set[map[slot]] || null;
};

// ─── Stat calculator ──────────────────────────────────────────────────────────
// Returns displayed stats with mastery applied
export function getGearStats(gearName, tier, gearLevel, mastery) {
  const rows = GEAR_DB[gearName];
  if (!rows) return null;
  const tierCode = tier === 'Legendary' ? 'L' : 'M';
  // Legendary has no level-0 row — fall back to Mythic 100 (the ascension base)
  let row = rows.find(r => r[0] === gearLevel && r[1] === tierCode);
  if (!row && tierCode === 'L' && gearLevel === 0) {
    row = rows.find(r => r[0] === 100 && r[1] === 'M');
  }
  if (!row) return null;
  const [, , heroMain, heroHp, escMain, escHp, troop, basePow] = row;
  const mult = 1 + (mastery * 0.10);
  return {
    heroMain: Math.round(heroMain * mult),
    heroHp:   Math.round(heroHp   * mult),
    escMain:  Math.round(escMain  * mult),
    escHp:    Math.round(escHp    * mult),
    troop:    Math.round(troop    * mult * 100) / 100,
    power:    Math.round(basePow  * mult),
  };
}

// Returns unlocked empowerment bonuses for a Legendary piece at given gear level
export function getUnlockedEmpowerments(gearName, tier, gearLevel) {
  if (tier !== 'Legendary') return [];
  const bonuses = EMPOWERMENT[gearName] || [];
  return bonuses.map(([threshold, label, value]) => ({
    threshold, label, value,
    unlocked: gearLevel >= threshold,
  }));
}
